    48â†’import { extractRepoName, getFilteredEvaluatorCount } from "./lib/formatters";
    49â†’import { shouldUseNestedGrouping as checkShouldUseNestedGrouping } from "./lib/grouping-utils";
    50â†’import { generateIssueHash } from "./lib/issue-hash";
    51â†’import { generateIssueKey } from "./lib/issue-utils";
    52â†’import type {
    53â†’	CategoryGroup,
    54â†’	EvaluationOutput,
    55â†’	EvaluatorFilter,
    56â†’	IndependentEvaluationOutput,
    57â†’	Issue,
    58â†’	UnifiedEvaluationOutput,
    59â†’} from "./types/evaluation";
    60â†’import {
    61â†’	getIssueFile,
    62â†’	getIssueSeverity,
    63â†’	getIssueType,
    64â†’	getMaxCategoryGroupSeverity,
    65â†’	getMaxIssueSeverity,
    66â†’	getSeverityLevel,
    67â†’	isIndependentFormat,
    68â†’	isUnifiedFormat,
    69â†’	parseEvaluatorResult,
    70â†’} from "./types/evaluation";
    71â†’import type {
    72â†’	EvaluationMode,
    73â†’	ICloneWarningEvent,
    74â†’	IContextAnalysisEvent,
    75â†’	IContextClocEvent,
    76â†’	IContextFoldersEvent,
    77â†’	IContextWarningEvent,
    78â†’	IDiscoveryCompletedEvent,
    79â†’	IEvaluatorProgressEvent,
    80â†’	IFileStartedEvent,
    81â†’	IJobCompletedEvent,
    82â†’	IJobFailedEvent,
    83â†’	IJobStartedEvent,
    84â†’	IProgressState,
    85â†’	SSEEvent,
    86â†’} from "./types/job";
    87â†’
    88â†’function AppContent() {
    89â†’	// Feature flags
    90â†’	const { assessmentEnabled, groupSelectEnabled, cloudMode } =
    91â†’		useFeatureFlags();
    92â†’
    93â†’	// URL-based routing
    94â†’	const navigate = useNavigate();
    95â†’	const { id: urlEvaluationId } = useParams<{ id: string }>();
    96â†’	const [searchParams, setSearchParams] = useSearchParams();
    97â†’
    98â†’	// Tab state from URL with smart defaults
    99â†’	const rawTab = searchParams.get("tab");
   100â†’	const handleTabChange = useCallback(
   101â†’		(tabId: string) => {
   102â†’			setSearchParams(
   103â†’				(prev) => {
   104â†’					prev.set("tab", tabId);
   105â†’					return prev;
   106â†’				},
   107â†’				{ replace: true },
   108â†’			);
   109â†’		},
   110â†’		[setSearchParams],
   111â†’	);
   112â†’
   113â†’	const [evaluationData, setEvaluationData] = useState<EvaluationOutput | null>(
   114â†’		null,
   115â†’	);
   116â†’	const [filters, setFilters] = useState<FilterState>({
   117â†’		severities: new Set(),
   118â†’		categories: new Set(),
   119â†’		evaluators: new Set(),
   120â†’		searchText: "",
   121â†’		bookmarkedOnly: false,
   122â†’	});
   123â†’	// Always show all issues (removed curated toggle)
   124â†’
   125â†’	// Evaluation job state
   126â†’	const [evaluationMode, setEvaluationMode] = useState<EvaluationMode>("idle");
   127â†’	const [currentJobId, setCurrentJobId] = useState<string | null>(null);
   128â†’	const [sseUrl, setSSEUrl] = useState<string | null>(null);
   129â†’	const [progressState, setProgressState] = useState<IProgressState | null>(
   130â†’		null,
   131â†’	);
   132â†’	const [apiError, setApiError] = useState<string | null>(null);
   133â†’	const [isLoadingFromUrl, setIsLoadingFromUrl] = useState(false);
   134â†’	const [currentRepositoryUrl, setCurrentRepositoryUrl] = useState<
   135â†’		string | null
   136â†’	>(null);
   137â†’	// Store evaluation logs to persist after completion
   138â†’	const [evaluationLogs, setEvaluationLogs] = useState<
   139â†’		Array<{ timestamp: Date; type: string; message: string }>
   140â†’	>([]);
   141â†’
   142â†’	// Parent evaluation data (for re-evaluations from remediation)
   143â†’	const [parentEvalId, setParentEvalId] = useState<string | undefined>();
   144â†’	const [parentEvalScore, setParentEvalScore] = useState<number | undefined>();
   145â†’	const [parentEvalGrade, setParentEvalGrade] = useState<string | undefined>();
   146â†’
   147â†’	// Issue selection state
   148â†’	const [selectedIssueKeys, setSelectedIssueKeys] = useState<Set<string>>(
   149â†’		new Set(),
   150â†’	);
   151â†’	const [issueKeyMap, setIssueKeyMap] = useState<Map<string, Issue>>(new Map());
   152â†’
   153â†’	// Feedback state
   154â†’	const [feedbackMap, setFeedbackMap] = useState<
   155â†’		Map<string, "like" | "dislike">
   156â†’	>(new Map());
   157â†’	const feedbackApi = useFeedbackApi();
   158â†’
   159â†’	// Bookmark state
   160â†’	const [bookmarkSet, setBookmarkSet] = useState<Set<string>>(new Set());
   161â†’	const bookmarkApi = useBookmarkApi();
   162â†’
   163â†’	// Selection persistence
   164â†’	const selectionApi = useSelectionApi();
   165â†’
   166â†’	// Derive currentEvaluationId from URL parameter
   167â†’	const currentEvaluationId = urlEvaluationId || null;
   168â†’
   169â†’	// Ref for completion timeout cleanup
   170â†’	const completionTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(
   171â†’		null,
   172â†’	);
   173â†’
   174â†’	// API hook
   175â†’	const api = useEvaluationApi();
   176â†’
   177â†’	// Evaluation history hook
   178â†’	const historyApi = useEvaluationHistory();
   179â†’
   180â†’	// Version hook
   181â†’	const { version } = useVersion();
   182â†’
   183â†’	// Ref for stable access to API function (avoids dependency array issues)
   184â†’	const loadEvaluationRef = useRef(historyApi.loadEvaluation);
   185â†’	loadEvaluationRef.current = historyApi.loadEvaluation;
   186â†’
   187â†’	// SSE event handler
   188â†’	const handleProgressEvent = useCallback(
   189â†’		(event: SSEEvent) => {
   190â†’			setProgressState((prev) => {
   191â†’				if (!prev) return prev;
   192â†’
   193â†’				const newState = { ...prev };
   194â†’
   195â†’				switch (event.type) {
   196â†’					// Clone events
   197â†’					case "clone.started": {
   198â†’						newState.logs = [
   199â†’							...prev.logs,
   200â†’							{
   201â†’								timestamp: new Date(),
   202â†’								type: "info",
   203â†’								message: "Cloning repository...",
   204â†’							},
   205â†’						];
   206â†’						break;
   207â†’					}
   208â†’
   209â†’					case "clone.completed": {
   210â†’						newState.logs = [
   211â†’							...prev.logs,
   212â†’							{
   213â†’								timestamp: new Date(),
   214â†’								type: "success",
   215â†’								message: "Repository cloned successfully",
   216â†’							},
   217â†’						];
   218â†’						break;
   219â†’					}
   220â†’
   221â†’					case "clone.warning": {
   222â†’						const data = (event as ICloneWarningEvent).data;
   223â†’						newState.logs = [
   224â†’							...prev.logs,
   225â†’							{
   226â†’								timestamp: new Date(),
   227â†’								type: "warning",
   228â†’								message: data.message,
   229â†’							},
   230â†’						];
   231â†’						break;
   232â†’					}
   233â†’
   234â†’					// Discovery events
   235â†’					case "discovery.started": {
   236â†’						newState.logs = [
   237â†’							...prev.logs,
   238â†’							{
   239â†’								timestamp: new Date(),
   240â†’								type: "info",
   241â†’								message: "Discovering context files...",
   242â†’							},
   243â†’						];
   244â†’						break;
   245â†’					}
   246â†’
   247â†’					case "discovery.completed": {
   248â†’						const data = (event as IDiscoveryCompletedEvent).data;
   249â†’						newState.logs = [
   250â†’							...prev.logs,
   251â†’							{
   252â†’								timestamp: new Date(),
   253â†’								type: "success",
   254â†’								message: `Found ${data.filesFound} context file(s)`,
   255â†’							},
   256â†’						];
   257â†’						break;
   258â†’					}
   259â†’
   260â†’					// Context sub-step events
   261â†’					case "context.cloc": {
   262â†’						const data = (event as IContextClocEvent).data;
   263â†’						if (data.status === "started") {
   264â†’							newState.logs = [
   265â†’								...prev.logs,
   266â†’								{
   267â†’									timestamp: new Date(),
   268â†’									type: "info",
   269â†’									message: "Analyzing codebase size...",
   270â†’								},
   271â†’							];
   272â†’						} else if (data.status === "completed") {
   273â†’							newState.logs = [
   274â†’								...prev.logs,
   275â†’								{
   276â†’									timestamp: new Date(),
   277â†’									type: "success",
   278â†’									message: `Codebase: ${data.totalLines?.toLocaleString() || "?"} lines across ${data.languageCount || "?"} languages`,
   279â†’								},
   280â†’							];
   281â†’						}
   282â†’						break;
   283â†’					}
   284â†’
   285â†’					case "context.folders": {
   286â†’						const data = (event as IContextFoldersEvent).data;
   287â†’						if (data.status === "started") {
   288â†’							newState.logs = [
   289â†’								...prev.logs,
   290â†’								{
   291â†’									timestamp: new Date(),
   292â†’									type: "info",
   293â†’									message: "Analyzing directory structure...",
   294â†’								},
   295â†’							];
   296â†’						} else if (data.status === "completed") {
   297â†’							newState.logs = [
   298â†’								...prev.logs,
   299â†’								{
   300â†’									timestamp: new Date(),
   301â†’									type: "success",
   302â†’									message: `Structure: ${data.folderCount || "?"} key directories`,
   303â†’								},
   304â†’							];
   305â†’						}
   306â†’						break;
   307â†’					}
   308â†’
   309â†’					case "context.analysis": {
   310â†’						const data = (event as IContextAnalysisEvent).data;
   311â†’						if (data.status === "started") {
   312â†’							newState.logs = [
   313â†’								...prev.logs,
   314â†’								{
   315â†’									timestamp: new Date(),
   316â†’									type: "info",
   317â†’									message: "Identifying project context...",
   318â†’								},
   319â†’							];
   320â†’						} else if (data.status === "completed") {
   321â†’							newState.logs = [
   322â†’								...prev.logs,
   323â†’								{
   324â†’									timestamp: new Date(),
   325â†’									type: "success",
   326â†’									message: "Project context identified",
   327â†’								},
   328â†’							];
   329â†’						}
   330â†’						break;
   331â†’					}
   332â†’
   333â†’					case "context.warning": {
   334â†’						const data = (event as IContextWarningEvent).data;
   335â†’						newState.logs = [
   336â†’							...prev.logs,
   337â†’							{
   338â†’								timestamp: new Date(),
   339â†’								type: "warning",
   340â†’								message: data.message,
   341â†’							},
   342â†’						];
   343â†’						break;
   344â†’					}
   345â†’
   346â†’					case "job.started": {
   347â†’						const data = (event as IJobStartedEvent).data;
   348â†’						newState.status = "running";
   349â†’						newState.totalFiles = data.totalFiles || 0;
   350â†’						newState.logs = [
   351â†’							...prev.logs,
   352â†’							{
   353â†’								timestamp: new Date(),
   354â†’								type: "info",
   355â†’								message: `Started evaluation (${data.evaluationMode} mode, ${data.totalFiles} file(s))`,
   356â†’							},
   357â†’						];
   358â†’						break;
   359â†’					}
   360â†’
   361â†’					case "file.started": {
   362â†’						const data = (event as IFileStartedEvent).data;
   363â†’						newState.currentFile = data.filePath;
   364â†’						newState.logs = [
   365â†’							...prev.logs,
   366â†’							{
   367â†’								timestamp: new Date(),
   368â†’								type: "info",
   369â†’								message: `Processing ${data.filePath}`,
   370â†’							},
   371â†’						];
   372â†’						break;
   373â†’					}
   374â†’
   375â†’					case "file.completed": {
   376â†’						newState.completedFiles = (prev.completedFiles || 0) + 1;
   377â†’						// Update percentage based on file progress
   378â†’						if (newState.totalFiles > 0) {
   379â†’							newState.percentage = Math.round(
   380â†’								(newState.completedFiles / newState.totalFiles) * 50,
   381â†’							);
   382â†’						}
   383â†’						break;
   384â†’					}
   385â†’
   386â†’					case "evaluator.progress": {
   387â†’						const data = (event as IEvaluatorProgressEvent).data;
   388â†’						newState.currentEvaluator = data.evaluatorName;
   389â†’						newState.completedEvaluators = data.evaluatorIndex;
   390â†’						newState.totalEvaluators = data.totalEvaluators;
   391â†’						// Update percentage based on evaluator progress
   392â†’						if (data.totalEvaluators > 0) {
   393â†’							const evaluatorProgress =
   394â†’								(data.evaluatorIndex / data.totalEvaluators) * 50;
   395â†’							newState.percentage = 50 + Math.round(evaluatorProgress);
   396â†’						}
   397â†’						// Include file context in log message when evaluating multiple files
   398â†’						const fileContext = data.currentFile
   399â†’							? ` on ${data.currentFile.split("/").pop()}`
   400â†’							: "";
   401â†’						newState.logs = [
   402â†’							...prev.logs,
   403â†’							{
   404â†’								timestamp: new Date(),
   405â†’								type: "info",
   406â†’								message: `Running ${data.evaluatorName}${fileContext} (${data.evaluatorIndex + 1}/${data.totalEvaluators})`,
   407â†’							},
   408â†’						];
   409â†’						break;
   410â†’					}
   411â†’
   412â†’					case "evaluator.completed": {
   413â†’						newState.completedEvaluators = (prev.completedEvaluators || 0) + 1;
   414â†’						break;
   415â†’					}
   416â†’
   417â†’					case "evaluator.retry": {
   418â†’						const data = event.data as {
   419â†’							evaluatorName: string;
   420â†’							attempt: number;
   421â†’							maxRetries: number;
   422â†’							error: string;
   423â†’							currentFile?: string;
   424â†’						};
   425â†’						const retriesRemaining = data.maxRetries - data.attempt;
   426â†’						newState.logs = [
   427â†’							...prev.logs,
   428â†’							{
   429â†’								timestamp: new Date(),
   430â†’								type: "warning",
   431â†’								message: `Retry ${data.attempt}/${data.maxRetries} for ${data.evaluatorName}: ${data.error.substring(0, 100)}${data.error.length > 100 ? "..." : ""} (${retriesRemaining} retries remaining)`,
   432â†’							},
   433â†’						];
   434â†’						break;
   435â†’					}
   436â†’
   437â†’					case "evaluator.timeout": {
   438â†’						const data = event.data as {
   439â†’							evaluatorName: string;
   440â†’							elapsedMs: number;
   441â†’							timeoutMs: number;
   442â†’							currentFile?: string;
   443â†’						};
   444â†’						const elapsedSec = Math.round(data.elapsedMs / 1000);
   445â†’						const timeoutSec = Math.round(data.timeoutMs / 1000);
   446â†’						newState.logs = [
   447â†’							...prev.logs,
   448â†’							{
   449â†’								timestamp: new Date(),
   450â†’								type: "error",
   451â†’								message: `Timeout: ${data.evaluatorName} exceeded ${timeoutSec}s limit (elapsed: ${elapsedSec}s)`,
   452â†’							},
   453â†’						];
   454â†’						break;
   455â†’					}
   456â†’
   457â†’					case "curation.started": {
   458â†’						const data = event.data;
   459â†’						const typeLabel =
   460â†’							data.issueType === "error"
   461â†’								? "errors"
   462â†’								: data.issueType === "suggestion"
   463â†’									? "suggestions"
   464â†’									: "issues";
   465â†’						newState.currentEvaluator = `Impact Curation (${typeLabel})`;
   466â†’						newState.logs = [
   467â†’							...prev.logs,
   468â†’							{
   469â†’								timestamp: new Date(),
   470â†’								type: "info",
   471â†’								message: `Curating top ${typeLabel} from ${data.totalIssues} total...`,
   472â†’							},
   473â†’						];
   474â†’						break;
   475â†’					}
   476â†’
   477â†’					case "curation.completed": {
   478â†’						const data = event.data;
   479â†’						const typeLabel =
   480â†’							data.issueType === "error"
   481â†’								? "errors"
   482â†’								: data.issueType === "suggestion"
   483â†’									? "suggestions"
   484â†’									: "issues";
   485â†’						newState.logs = [
   486â†’							...prev.logs,
   487â†’							{
   488â†’								timestamp: new Date(),
   489â†’								type: "success",
   490â†’								message: `Impact curation completed for ${typeLabel} (${data.curatedCount} selected)`,
   491â†’							},
   492â†’						];
   493â†’						break;
   494â†’					}
   495â†’
   496â†’					case "evaluation.warning": {
   497â†’						const data = event.data;
   498â†’						newState.logs = [
   499â†’							...prev.logs,
   500â†’							{
   501â†’								timestamp: new Date(),
   502â†’								type: "warning",
   503â†’								message: data.message || "Some evaluators encountered errors",
   504â†’							},
   505â†’						];
   506â†’						break;
   507â†’					}
   508â†’
   509â†’					case "job.completed": {
   510â†’						const data = (event as IJobCompletedEvent).data;
   511â†’						newState.status = "completed";
   512â†’						newState.percentage = 100;
   513â†’						newState.logs = [
   514â†’							...prev.logs,
   515â†’							{
   516â†’								timestamp: new Date(),
   517â†’								type: "success",
   518â†’								message: `Evaluation completed in ${Math.round(data.duration / 1000)}s`,
   519â†’							},
   520â†’						];
   521â†’						// Preserve logs for display in Summary after completion
   522â†’						setEvaluationLogs(newState.logs);
   523â†’						// Set the evaluation data
   524â†’						setEvaluationData(data.result);
   525â†’						setEvaluationMode("completed");
   526â†’						// Reset job state after a short delay (user is already at /evaluation/:jobId)
   527â†’						// Clear any existing timeout first
   528â†’						if (completionTimeoutRef.current) {
   529â†’							clearTimeout(completionTimeoutRef.current);
   530â†’							completionTimeoutRef.current = null;
   531â†’						}
   532â†’						completionTimeoutRef.current = setTimeout(() => {
   533â†’							setCurrentJobId(null);
   534â†’							setSSEUrl(null);
